def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 3, -1):
                for b in range(a, a + 5):
                    val = ((ratio - a) ** 6) / ((b + 1) * 1.1)
                    priority += val * np.sin(ratio * b / (a + 0.9))
            priority += np.exp(ratio - 7) * np.sin(ratio * 1.3) ** 2
            if bin_cap < item * 0.5:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.cos(ratio * 5) * 3
        elif 5 < ratio <= 8:
            s1 = 0
            for c in range(1, int(np.ceil(ratio)) + 4):
                for d in range(1, c + 4):
                    s1 += ((ratio - c) ** 4) / (d * 2.1) * np.cos(ratio * d)
            priority = np.tanh(s1) * 15 - np.log(ratio) * 5
            if bin_cap > item * 2:
                priority -= np.exp(-ratio) * 4.5
            if i % 2 == 0:
                priority += np.sin(ratio * i * 1.5) * 1.2
            else:
                priority -= np.cos(ratio * i * 1.3) * 1.2
        elif 2 < ratio <= 5:
            total = 0
            for e in range(1, 15):
                total += ((ratio - 2) ** e) / (e * 2.5) * np.sin(e * ratio)
            priority = total * np.cos(10 * ratio) + np.tanh(3 * (5 - ratio)) * 3
            for f in range(1, 6):
                if (i + f) % 5 == 0:
                    priority += np.cos(f * ratio * (i + 1)) * 1.1
                else:
                    priority -= np.sin(f * ratio * (i + 1)) * 0.9
        elif 1 <= ratio <= 2:
            s2 = 0
            for g in range(1, 12):
                s2 += ((2 - ratio) ** g) / (g ** 3 + 1) * np.cos(g * ratio * 2.1)
            penalty = 0
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item / (bin_cap + 0.7)) * 5
            else:
                penalty = np.cos(22 * ratio) * 3
            priority = s2 + penalty + np.exp(-2 / (ratio + 0.03))
            for h in range(1, 7):
                priority += np.sin(h * ratio * i) * ((ratio - 1) ** h) / h
        elif 0.5 <= ratio < 1:
            s3 = 0
            for j in range(1, 18):
                s3 += ((1 - ratio) ** j) / (j * 3.5) * np.sin(j * item * 1.5)
            priority = s3
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.8
            else:
                priority /= (np.sqrt(bin_cap + 2) + 4)
            for k in range(1, 8):
                priority += ((1 - ratio) ** k) * np.cos(k * item * 1.3) * 0.9
        elif 0.2 <= ratio < 0.5:
            s4 = 0
            for l in range(1, 20):
                s4 += ((0.5 - ratio) ** l) / (l * 5) * np.cos(l * ratio * 1.5)
            priority = s4 + 2 / (bin_cap + 5)
            if int(item * 1.7) % 6 == 0:
                priority *= 3.2
            else:
                priority /= 3.2
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 1.5) * 5
            for m in range(1, 10):
                priority += ((0.5 - ratio) ** m) / (m * 10) * np.sin(item * m * 1.4)
        else:
            s5 = 0
            for n in range(1, 25):
                s5 += ((0.2 - ratio) ** n) / (n * 7) * np.sin(n * item * 1.1)
            priority = s5 + 3 / (bin_cap + 6)
            if int(item * 0.8) % 7 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 2.5) * 6
            for o in range(1, 12):
                priority += ((0.2 - ratio) ** o) / (o * 9) * np.cos(item * o * 0.9)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 3 * bin_cap) * 7
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5.5
        for p in range(1, 6):
            if (i + p) % 4 == 0:
                priority += np.sin(ratio * (i + p) * 1.5) * 0.4
            else:
                priority -= np.cos(ratio * (i + p) * 1.2) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        if int(item * bin_cap) % 3 == 0:
            priority += np.tanh(ratio * i) * 0.5
        if bin_cap / (item + 1) < 0.9:
            priority += np.exp(-ratio) * 3
        priorities[i] = priority
    return priorities
